@namespace sv_8fa9aee4431a466299ff30892e6e7829.Components.JobApplication

<div class="step-indicator">
    @for (int i = 0; i < StepNames.Length; i++)
    {
        var step = i;
        var isCompleted = CompletedSteps.Contains(step);
        var isCurrent = step == CurrentStep;
        var isClickable = isCompleted && !isCurrent;

        <div class="step @(isCurrent ? "current" : "") @(isCompleted && !isCurrent ? "completed" : "") @(!isCurrent && !isCompleted ? "future" : "")"
             @onclick="() => { if (isClickable) OnStepClicked.InvokeAsync(step); }"
             role="@(isClickable ? "button" : "")"
             style="@(isClickable ? "cursor: pointer;" : "")">
            <div class="step-circle">
                @if (isCompleted && !isCurrent)
                {
                    <span>✓</span>
                }
                else
                {
                    <span>@(step + 1)</span>
                }
            </div>
            <div class="step-label">@StepNames[step]</div>
        </div>

        @if (i < StepNames.Length - 1)
        {
            <div class="step-connector @(CompletedSteps.Contains(i) ? "completed" : "")"></div>
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = [];
    [Parameter, EditorRequired] public string[] StepNames { get; set; } = [];
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }
}

.step-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 2rem;
    padding: 1rem 0;
    flex-wrap: wrap;
    gap: 0.25rem 0;
}

.step {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.5rem;
    min-width: 80px;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.875rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #adb5bd;
    transition: all 0.2s;
}

.step.current .step-circle {
    border-color: #0d6efd;
    background: #0d6efd;
    color: #fff;
}

.step.completed .step-circle {
    border-color: #198754;
    background: #198754;
    color: #fff;
}

.step-label {
    font-size: 0.75rem;
    text-align: center;
    color: #adb5bd;
    max-width: 90px;
}

.step.current .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step.completed .step-label {
    color: #198754;
}

.step-connector {
    flex: 1;
    height: 2px;
    background: #dee2e6;
    margin: 0 0.25rem;
    margin-bottom: 1.5rem;
    max-width: 60px;
    min-width: 20px;
    transition: background 0.2s;
}

.step-connector.completed {
    background: #198754;
}

