@namespace sv_8fa9aee4431a466299ff30892e6e7829.Components.JobApplication
@using sv_8fa9aee4431a466299ff30892e6e7829.Services

@inject IApplicationService ApplicationService

<div class="step-content">
    <h4 class="mb-4">Personal Information</h4>

    <div class="mb-3">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control @ValidationClass("FullName")"
               @bind="Model.FullName" @bind:event="oninput" />
        @if (errors.ContainsKey("FullName"))
        {
            <div class="invalid-feedback">@errors["FullName"]</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @ValidationClass("Email")"
               @bind="Model.Email" @bind:event="oninput" />
        @if (errors.ContainsKey("Email"))
        {
            <div class="invalid-feedback">@errors["Email"]</div>
        }
    </div>

    <div class="mb-3">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
