@namespace sv_8fa9aee4431a466299ff30892e6e7829.Components.JobApplication

<div class="step-content">
    <h4 class="mb-4">Work History</h4>

    @for (int i = 0; i < Entries.Count; i++)
    {
        var index = i;
        <WorkEntryEditor Entry="Entries[index]" Index="index"
                         CanRemove="Entries.Count > 1"
                         OnRemove="() => RemoveEntry(index)" />
    }

    <button class="btn btn-outline-secondary mb-3" @onclick="AddEntry">
        + Add Another Position
    </button>

    @if (showError)
    {
        <div class="alert alert-danger">Please complete at least one work entry (company and title are required).</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="HandleNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private bool showError;

    private void AddEntry() => Entries.Add(new WorkEntryModel());

    private void RemoveEntry(int index)
    {
        if (Entries.Count > 1)
            Entries.RemoveAt(index);
    }

    private async Task HandleNext()
    {
        showError = Entries.TrueForAll(e =>
            string.IsNullOrWhiteSpace(e.Company) || string.IsNullOrWhiteSpace(e.Title));
        if (!showError)
            await OnNext.InvokeAsync();
    }
}

