@namespace sv_8fa9aee4431a466299ff30892e6e7829.Components.JobApplication

<div class="step-content">
    <h4 class="mb-4">Cover Letter</h4>

    <div class="mb-3">
        <textarea class="form-control" rows="12" maxlength="@MaxLength"
                  @bind="Model.CoverLetter" @bind:event="oninput"
                  placeholder="Write your cover letter here…"></textarea>
        <div class="form-text text-end">
            @Model.CoverLetter.Length / @MaxLength characters
        </div>
    </div>

    <div class="d-flex justify-content-between">
        <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-primary" @onclick="OnNext">Next</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private const int MaxLength = 2000;
}

@namespace sv_8fa9aee4431a466299ff30892e6e7829.Components.JobApplication
@using sv_8fa9aee4431a466299ff30892e6e7829.Services

@inject IApplicationService ApplicationService

<div class="step-content">
    <h4 class="mb-4">Review & Submit</h4>

    @if (isSubmitted)
    {
        <div class="alert alert-success text-center py-4">
            <h5 class="alert-heading">Application Submitted Successfully!</h5>
            <p class="mb-1">Your application ID is: <strong>#@applicationId</strong></p>
            <p class="mb-0">Thank you for applying. We will review your application and get back to you.</p>
        </div>
    }
    else
    {
        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Personal Information</strong>
                <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
            </div>
            <div class="card-body">
                <div class="row">
                    <div class="col-md-6 mb-1"><strong>Name:</strong> @Model.Personal.FullName</div>
                    <div class="col-md-6 mb-1"><strong>Email:</strong> @Model.Personal.Email</div>
                    <div class="col-md-6 mb-1"><strong>Phone:</strong> @Model.Personal.Phone</div>
                    <div class="col-md-6 mb-1"><strong>Address:</strong> @Model.Personal.Address</div>
                </div>
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Work History</strong>
                <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
            </div>
            <div class="card-body">
                @foreach (var entry in Model.WorkEntries)
                {
                    <div class="mb-3">
                        <div><strong>@entry.Title</strong> at @entry.Company</div>
                        <div class="text-muted">
                            @(entry.StartDate?.ToString("MMM yyyy") ?? "N/A") –
                            @(entry.IsCurrent ? "Present" : (entry.EndDate?.ToString("MMM yyyy") ?? "N/A"))
                        </div>
                        @if (!string.IsNullOrWhiteSpace(entry.Description))
                        {
                            <div class="mt-1">@entry.Description</div>
                        }
                    </div>
                }
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>References</strong>
                <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
            </div>
            <div class="card-body">
                @foreach (var reference in Model.References)
                {
                    <div class="mb-2">
                        <strong>@reference.Name</strong> (@reference.Relationship)<br />
                        @reference.Email · @reference.Phone
                    </div>
                }
            </div>
        </div>

        <div class="card mb-3">
            <div class="card-header d-flex justify-content-between align-items-center">
                <strong>Cover Letter</strong>
                <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
            </div>
            <div class="card-body">
                <p style="white-space: pre-wrap;" class="mb-0">@Model.CoverLetter</p>
            </div>
        </div>

        @if (!string.IsNullOrEmpty(submitError))
        {
            <div class="alert alert-danger">@submitError</div>
        }

        <div class="d-flex justify-content-between">
            <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
            <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@isSubmitting">
                @if (isSubmitting)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                    <span>Submitting…</span>
                }
                else
                {
                    <span>Submit Application</span>
                }
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public ApplicationFormModel Model { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnEditStep { get; set; }

    private bool isSubmitting;
    private bool isSubmitted;
    private int applicationId;
    private string? submitError;

    private async Task HandleSubmit()
    {
        isSubmitting = true;
        submitError = null;

        try
        {
            applicationId = await ApplicationService.SubmitApplicationAsync(Model.ToSubmission());
            isSubmitted = true;
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

