@page "/apply"
@using sv_8fa9aee4431a466299ff30892e6e7829.Components.JobApplication
@using sv_8fa9aee4431a466299ff30892e6e7829.Models

@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep"
                   CompletedSteps="completedSteps"
                   StepNames="stepNames"
                   OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="model.Personal" OnNext="NextStep" />
            break;
        case 1:
            <WorkHistoryStep Entries="model.WorkEntries" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 2:
            <ReferencesStep References="model.References" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 3:
            <CoverLetterStep Model="model" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 4:
            <ReviewStep Model="model" OnBack="PreviousStep" OnEditStep="GoToStep" />
            break;
    }
</div>

@code {
    private readonly ApplicationFormModel model = new();
    private int currentStep;
    private readonly HashSet<int> completedSteps = [];

    private static readonly string[] stepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    private void NextStep()
    {
        completedSteps.Add(currentStep);
        if (currentStep < stepNames.Length - 1)
            currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 0)
            currentStep--;
    }

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
            currentStep = step;
    }
}

